class Solution(object):
    def countArrays(self, original, bounds):
        n = len(original)
        # copy[i] = original[i] - original[0] + copy[0]
        # So copy[0] must satisfy: bounds[i][0] <= original[i] - original[0] + copy[0] <= bounds[i][1]
        # => bounds[i][0] - original[i] + original[0] <= copy[0] <= bounds[i][1] - original[i] + original[0]
        lo, hi = bounds[0][0], bounds[0][1]
        for i in range(1, n):
            diff = original[i] - original[0]
            lo = max(lo, bounds[i][0] - diff)
            hi = min(hi, bounds[i][1] - diff)
        return max(0, hi - lo + 1)
